<template>
    <NavbarComponent/>
    <NavigationComponent/>
    <main style="min-height:100vh">
    <div class="container">
        <div class="row mt-5">
            <div class="col">
                <router-link :to="{name:'ppdb.index'}" class="btn btn-primary px-5 py-3"><i class="bi bi-house"></i> Home</router-link>
            </div>
        </div>
         <!-- v-for="alias in berita" :key="alias.id" -->
        <div  class="col">
            <div class="row text-center mt-5">
                <div class="col-md-12 mb-3">
                    <h1>{{ pengumuman.judul}}</h1>
                            <img v-bind:src="'http://wawanindrawan.nurulfikri.com/capstone-km/'+pengumuman.berkas" class="img-fluid shadow-md" style="width:40%;background:#eaeaea">

                </div>
                <div class="col-md-12">
                </div>
            </div>
            <div class="row p-3">
                <div class="col-md-12">
                    <p>{{ pengumuman.isi }}</p>
                </div>
            </div>
        </div>

    </div>
    </main>
    <FooterComponent />
</template>

<script>
import NavbarComponent from '../../components/NavbarComponent.vue';
import NavigationComponent from '../../components/NavigationComponent.vue';
import FooterComponent from '../../components/FooterComponent.vue';


import axios from 'axios'
import { onMounted, ref } from 'vue';
import { useRoute } from 'vue-router'
export default{
     setup(){
        // reactive state
        let pengumuman = ref([]);
        const route = useRoute();

            console.log(route.params.id);
        onMounted(()=>{
            axios.get(`http://wawanindrawan.nurulfikri.com/capstone-km/api/pengumuman/detail/${route.params.id}`)
                .then((result) => {
                    pengumuman.value = result.data.pengumuman
                }).catch((err) => {
                    console.log(err.response)
                });
        });
        return {
            pengumuman
        }
    },
    name: "PengumumanView",
    components: { NavbarComponent, NavigationComponent, FooterComponent }
}

</script>